import React, { Fragment, useCallback, useEffect, useMemo, useState } from 'react';
import { renderToString } from 'react-dom/server';
import PropTypes from 'prop-types';
import { navigate, useIntl } from 'gatsby-plugin-intl';
import { graphql } from 'gatsby';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';
import { useFlexSearch } from 'react-use-flexsearch';

// Utils
import { getAlternateLangLinks, truncateStringToWord } from '../utils/gatsby-frontend-helpers';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import PostsList from '../components/PostsList';
import CustomPagination from '../components/CustomPagination';

const useStyles = makeStyles((theme) => ({
    searchText: {
        margin: '15px 0',
    },
    simplePostsListWrapper: {
        marginBottom: '10px',
    },
    highlightedQuery: {
        ...theme?.palette?.type === 'light' && {
            backgroundColor: '#edff5c',
            color: '#000000',
        },
        ...theme?.palette?.type === 'dark' && {
            backgroundColor: '#00909e',
            color: '#ffffff',
        },
        padding: '0 2px',
    },
}));

const SearchPage = ({ location, data, pageContext, params }) => {
    const intl = useIntl();
    const classes = useStyles();
    const postsPerPage = 10;
    const [query = '', pageNumberString = '1'] = (params['*'] || '').split('/');
    const currentPageNumber = parseInt(pageNumberString, 10);
    const [noResultsTextId, setNoResultsTextId] = useState('loading');
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    const allResults = useFlexSearch(
        query,
        data.localSearchPage.index,
        data.localSearchPage.store
    ).filter((page) => page.locale === intl.locale);

    const totalPageNumber = Math.ceil(allResults.length / postsPerPage);
    const results = allResults.slice((currentPageNumber - 1) * postsPerPage, postsPerPage * currentPageNumber);

    const getExcerpt = useCallback((text, length) => {
        const regex = new RegExp(`\\b(${query.toLowerCase()})\\b`);
        const matchedRegex = text.toLowerCase().match(regex);

        // TODO normalize the text with accent
        // so the word boundary works properly
        // const normalizedQuery = actualQuery.normalize('NFD').replace(/\p{Diacritic}/gu, '');
        if (matchedRegex?.length) {
            // now let's create a regex using the actual word found, capital-sensitive
            const actualQuery = text.substr(matchedRegex.index, query.length);
            const actualRegex = new RegExp(`\\b(${actualQuery})\\b`, 'g');

            // start of the excerpt
            const excerptEnd = truncateStringToWord(
                text.substr(matchedRegex.index),
                length,
                true
            );

            // yolo let's reverse the string and use the same function for the
            // beginning of the excerpt too
            const excerptStart = truncateStringToWord(
                text.substr(0, matchedRegex.index).split('').reverse().join(''),
                length,
                true
            );

            const excerpt = `${excerptStart.split('').reverse().join('')}${excerptEnd}`;

            const highlightedQuery = renderToString(
                <span className={classes.highlightedQuery}>
                    {actualQuery}
                </span>
            );

            return excerpt.replace(actualRegex, highlightedQuery);
        }

        return truncateStringToWord(text, length, true);
    }, [classes.highlightedQuery, query]);

    const postsLoop = useMemo(
        () => results.map((postData) => ({
            node: {
                excerpt: getExcerpt(postData.body, 60),
                fields: {
                    locale: postData.locale,
                    path: postData.path,
                    slug: postData.slug,
                },
                frontmatter: {
                    date: postData.date,
                    hideExcerpt: false,
                    title: postData.title,
                    tags: postData.tags,
                },
            },
        })).sort(
            (a, b) =>
                new Date(b.node.frontmatter.date) - new Date(a.node.frontmatter.date)
        ),
        [results, getExcerpt]
    );

    // for some reason the first render always returns no results
    // so we need this to display the "Loading" and then the "No results" text
    useEffect(() => {
        const urlParams = new URLSearchParams(location.search);
        const urlQuery = urlParams.get('q') || '';
        if (urlQuery) {
            navigate(`/search/${urlQuery}`);
        } else if (!query) {
            navigate('/');
        }

        setNoResultsTextId('no_results');
    }, [results, query, location.search]);

    const titleTranslationKey = postsLoop.length > 0 ? 'search_results' : 'search';

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: titleTranslationKey })}
                keywords={[query]}
                robots="noindex"
                alternateLangLinks={alternateLangLinks}
            />
            <Typography
                className={classes.searchText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: titleTranslationKey })}
            </Typography>
            {postsLoop.length > 0 && (
                <Fragment>
                    <Typography
                        className={classes.searchText}
                        color="textPrimary"
                        variant="h6"
                    >
                        {intl.formatMessage({ id: 'search_results_for' }, {
                            query,
                            quantity: allResults.length,
                        })}
                    </Typography>
                    <PostsList
                        posts={postsLoop}
                        locale={intl.locale}
                        className={classes.simplePostsListWrapper}
                    />
                </Fragment>
            )}
            {postsLoop.length === 0 && (
                <Typography
                    className={classes.searchText}
                    color="textPrimary"
                    variant="body2"
                >
                    {intl.formatMessage({ id: noResultsTextId })}
                </Typography>
            )}
            {totalPageNumber > 1 && (
                <CustomPagination
                    currentPageNumber={currentPageNumber}
                    totalPageNumber={totalPageNumber}
                    onChange={(event, pageNumber) => {
                        navigate(`/search/${query}/${pageNumber}`);
                    }}
                />
            )}
        </Layout>
    );
};

SearchPage.propTypes = {
    data: PropTypes.shape({
        site: PropTypes.shape({
            siteMetadata: PropTypes.shape({
                siteUrl: PropTypes.string.isRequired,
            }).isRequired,
        }).isRequired,
        localSearchPage: PropTypes.shape({
            index: PropTypes.string.isRequired,
            store: PropTypes.object.isRequired,
        }).isRequired,
    }).isRequired,
};

export default SearchPage;

export const pageQuery = graphql`
    query {
        localSearchPage {
            index
            store
        }
        site {
            siteMetadata {
                siteUrl
            }
        }
    }
`;
